// Pull out the useful fields from the Alpha Vantage response
const quote = $input.first().json['Global Quote'];

if (!quote) {
  throw new Error('No quote data returned. Check your API key or symbol.');
}

const symbol = quote['01. symbol'];
const price = parseFloat(quote['05. price']);
const change = parseFloat(quote['09. change']);
const changePercent = quote['10. change percent'];

// Simple signal logic (for learning purposes only)
let signal = 'HOLD';
if (parseFloat(changePercent) > 2) signal = 'STRONG MOVE UP';
if (parseFloat(changePercent) < -2) signal = 'STRONG MOVE DOWN';

return [{
  json: {
    symbol,
    price,
    change,
    changePercent,
    signal,
    summary: `${symbol}: $${price} (${changePercent}) — ${signal}`,
    date: new Date().toISOString().split('T')[0]
  }
}];
